import 'dotenv/config';
import postgres from 'postgres';

const sql = postgres(process.env.DATABASE_URL);

// ─── Helpers ──────────────────────────────────────────────────────────────────
function slug(str) {
  return str.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}

async function batchInsert(items, batchSize, insertFn) {
  for (let i = 0; i < items.length; i += batchSize) {
    const batch = items.slice(i, i + batchSize);
    await Promise.all(batch.map(insertFn));
  }
}

// ─── Genres ───────────────────────────────────────────────────────────────────
const GENRES = [
  "Action","Adventure","Animation","Comedy","Crime","Documentary",
  "Drama","Fantasy","Horror","Musical","Mystery","Romance",
  "Sci-Fi","Thriller","Western","Biography","History","Sport",
  "War","Family","Superhero","Noir","Psychological","Cult Classic"
];

console.log("Seeding genres...");
for (const g of GENRES) {
  await sql`INSERT INTO genres (name, slug) VALUES (${g}, ${slug(g)}) ON CONFLICT DO NOTHING`;
}
const genreRows = await sql`SELECT id, name FROM genres`;
const genreMap = Object.fromEntries(genreRows.map(r => [r.name, r.id]));

