console.log("Seeding persons...");
const personIdMap = {};
for (const p of PERSONS) {
  const s = slug(p.name);
  try {
    const rows = await sql`
      INSERT INTO persons (name, slug, photo_url, bio, birth_date, birth_place, known_for)
      VALUES (${p.name}, ${s}, ${p.photoUrl || null}, ${p.bio || null}, ${p.birthDate || null}, ${p.birthPlace || null}, ${p.knownFor || null})
      ON CONFLICT (slug) DO NOTHING
      RETURNING id
    `;
    if (rows.length > 0) personIdMap[p.name] = rows[0].id;
  } catch(e) {
    // Try to fetch existing
  }
}
// Fetch all person IDs
const personRows = await sql`SELECT id, name FROM persons`;
for (const r of personRows) personIdMap[r.name] = r.id;

