// ─── Insert Movies ─────────────────────────────────────────────────────────────
console.log("Seeding movies...");
const movieIdMap = {};
const seenSlugs = new Set();

for (let i = 0; i < MOVIES.length; i++) {
  const m = MOVIES[i];
  let s = slug(m.title);
  let finalSlug = s;
  if (seenSlugs.has(finalSlug)) {
    finalSlug = `${s}-${m.year}`;
  }
  if (seenSlugs.has(finalSlug)) {
    finalSlug = `${s}-${m.year}-${i}`;
  }
  seenSlugs.add(finalSlug);

  try {
    const rows = await sql`
      INSERT INTO movies (title, slug, year, runtime, synopsis, poster_url, backdrop_url, imdb_rating, rt_score, letterboxd_rating, mpaa_rating, language, country, budget, box_office, featured, trending, status)
      VALUES (${m.title}, ${finalSlug}, ${m.year||null}, ${m.runtime||null}, ${m.synopsis||null}, ${m.posterUrl||null}, ${m.backdropUrl||null}, ${m.imdbRating||null}, ${m.rtScore||null}, ${m.letterboxdRating||null}, ${m.mpaaRating||null}, ${m.language||null}, ${m.country||null}, ${m.budget||null}, ${m.boxOffice||null}, ${m.featured||false}, ${m.trending||false}, 'released')
      ON CONFLICT (slug) DO NOTHING
      RETURNING id
    `;
    if (rows.length > 0) movieIdMap[m.title] = rows[0].id;
  } catch(e) {
    console.warn(`Skipping movie "${m.title}": ${e.message}`);
  }
}

// Fetch all movie IDs
const movieRows = await sql`SELECT id, title FROM movies`;
for (const r of movieRows) {
  if (!movieIdMap[r.title]) movieIdMap[r.title] = r.id;
}

// ─── Insert Movie Genres ───────────────────────────────────────────────────────
