let genreCount = 0;
for (const m of MOVIES) {
  const movieId = movieIdMap[m.title];
  if (!movieId) continue;
  for (const g of (m.genres || [])) {
    const genreId = genreMap[g];
    if (!genreId) continue;
    try {
      await sql`INSERT INTO movie_genres (movie_id, genre_id) VALUES (${movieId}, ${genreId}) ON CONFLICT DO NOTHING`;
      genreCount++;
    } catch(e) {}
  }
}

